import React, { useState, useMemo } from 'react';
import { useSearchParams } from 'react-router-dom';
import {
  Heading,
  Text,
  Input,
  useConfirm,
  ConfirmDialog,
  toast,
} from '@adopt-dont-shop/lib.components';
import {
  FiSearch,
  FiMessageSquare,
  FiAlertCircle,
  FiCheckCircle,
  FiEye,
  FiFlag,
  FiTrash,
} from 'react-icons/fi';
import {
  PageContainer,
  PageHeader,
  HeaderLeft,
  FilterBar,
  FilterGroup,
  FilterLabel,
  SearchInputWrapper,
  Select,
  Badge,
  StatsBar,
  StatCard,
  StatIcon,
  StatDetails,
  StatLabel,
  StatValue,
} from '../components/ui';
import { DataTable, type Column } from '../components/data';
import {
  useAdminChats,
  useAdminChatStats,
  useAdminChatMutations,
  type Conversation,
} from '@adopt-dont-shop/lib.chat';
import { ChatDetailModal } from '../components/modals';
import * as styles from './Messages.css';

const getStatusDotClass = (status: string): string => {
  switch (status) {
    case 'active':
      return styles.statusDotActive;
    case 'flagged':
      return styles.statusDotFlagged;
    case 'archived':
      return styles.statusDotArchived;
    default:
      return styles.statusDotDefault;
  }
};

const Messages: React.FC = () => {
  // ADS: deep-link support — initialise from ?chatId= so the triage inbox
  // can navigate users straight to a specific chat thread.
  const [searchParams, setSearchParams] = useSearchParams();
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [selectedChatId, setSelectedChatId] = useState<string | null>(() =>
    searchParams.get('chatId')
  );
  const { confirm, confirmProps } = useConfirm();

  const handleCloseChatModal = () => {
    setSelectedChatId(null);
    if (searchParams.has('chatId')) {
      setSearchParams(
        prev => {
          const next = new URLSearchParams(prev);
          next.delete('chatId');
          return next;
        },
        { replace: true }
      );
    }
  };

  const filters = useMemo(() => {
    const apiFilters: {
      status?: string;
      search?: string;
      page?: number;
      limit?: number;
    } = {};

    if (statusFilter !== 'all') {
      apiFilters.status = statusFilter;
    }
    if (searchQuery) {
      apiFilters.search = searchQuery;
    }

    return apiFilters;
  }, [statusFilter, searchQuery]);

  const { data: chatsData, isLoading, error: chatsError, refetch } = useAdminChats(filters);
  const { data: statsData } = useAdminChatStats();
  const { deleteChat, updateChatStatus } = useAdminChatMutations();

  const chats = chatsData?.data || [];
  const loading = isLoading;

  const stats = {
    total: statsData?.totalChats || 0,
    active: statsData?.activeChats || 0,
    messages: statsData?.totalMessages || 0,
    avgMessages: Math.round(statsData?.averageMessagesPerChat || 0),
  };

  const formatTimestamp = (timestamp: string) => {
    const date = new Date(timestamp);
    const now = new Date();
    const diffMs = now.getTime() - date.getTime();
    const diffMins = Math.floor(diffMs / 60000);
    const diffHours = Math.floor(diffMs / 3600000);
    const diffDays = Math.floor(diffMs / 86400000);

    if (diffMins < 60) {
      return `${diffMins}m ago`;
    } else if (diffHours < 24) {
      return `${diffHours}h ago`;
    } else if (diffDays < 7) {
      return `${diffDays}d ago`;
    } else {
      return date.toLocaleDateString('en-GB', {
        day: '2-digit',
        month: 'short',
      });
    }
  };

  const getStatusBadge = (status?: string) => {
    switch (status) {
      case 'active':
        return <Badge $variant='success'>Active</Badge>;
      case 'blocked':
        return <Badge $variant='danger'>Blocked</Badge>;
      case 'closed':
        return <Badge $variant='warning'>Closed</Badge>;
      case 'archived':
        return <Badge $variant='neutral'>Archived</Badge>;
      default:
        return <Badge $variant='neutral'>{status || 'active'}</Badge>;
    }
  };

  const handleDeleteChat = async (chatId: string, e: React.MouseEvent) => {
    e.stopPropagation();

    const confirmed = await confirm({
      title: 'Delete Conversation',
      message: 'Are you sure you want to delete this conversation? This action cannot be undone.',
      confirmText: 'Delete',
      cancelText: 'Cancel',
      variant: 'danger',
    });

    if (confirmed) {
      try {
        await deleteChat.mutateAsync(chatId);
        await refetch();
      } catch (error) {
        console.error('Failed to delete chat:', error);
        toast.error(
          `Failed to delete chat: ${error instanceof Error ? error.message : 'Unknown error'}`,
          {
            action: {
              label: 'Retry',
              onClick: () => {
                void handleDeleteChat(chatId, e);
              },
            },
          }
        );
      }
    }
  };

  const handleUpdateStatus = async (chatId: string, status: string, e: React.MouseEvent) => {
    e.stopPropagation();

    if (status === 'archived') {
      const confirmed = await confirm({
        title: 'Archive Conversation',
        message: 'Are you sure you want to archive this conversation?',
        confirmText: 'Archive',
        cancelText: 'Cancel',
        variant: 'warning',
      });

      if (!confirmed) {
        return;
      }
    }

    try {
      await updateChatStatus.mutateAsync({ chatId, status });
      await refetch();
    } catch (error) {
      console.error('Failed to update chat status:', error);
    }
  };

  const columns: Column<Conversation>[] = [
    {
      id: 'status',
      header: '',
      accessor: row => <div className={getStatusDotClass(row.status || 'active')} />,
      width: '40px',
    },
    {
      id: 'conversation',
      header: 'Conversation',
      accessor: row => (
        <div className={styles.messagePreview}>
          <div className={styles.messageParticipants}>
            {row.participants.map((p, i) => (
              <React.Fragment key={p.id}>
                {i > 0 && ' ↔ '}
                {p.name}
              </React.Fragment>
            ))}
          </div>
          <div className={styles.messageSubject}>
            Chat #{row.id.slice(-6)}
            {row.rescueName && ` - ${row.rescueName}`}
            {row.petId && ` (Pet: ${row.petId.slice(-6)})`}
          </div>
          <div className={styles.messageMeta}>
            <span>{row.participants.length} participants</span>
            {row.unreadCount > 0 && <span>• {row.unreadCount} unread</span>}
            <span>• Last activity: {formatTimestamp(row.updatedAt)}</span>
          </div>
        </div>
      ),
      width: '420px',
    },
    {
      id: 'lastMessage',
      header: 'Last Message',
      accessor: row => (
        <div className={styles.lastMessageCell}>
          {row.lastMessage?.content || (
            <span className={styles.noMessagesPlaceholder}>No messages</span>
          )}
        </div>
      ),
      width: '250px',
    },
    {
      id: 'participants',
      header: 'Participants',
      accessor: row => (
        <div className={styles.participantsList}>
          {row.participants.slice(0, 2).map(p => (
            <div key={p.id} className={styles.participantInfo}>
              <div className={styles.participantName}>{p.name}</div>
              <div className={styles.participantRole}>{p.type}</div>
            </div>
          ))}
          {row.participants.length > 2 && (
            <div className={styles.participantMore}>+{row.participants.length - 2} more</div>
          )}
        </div>
      ),
      width: '180px',
    },
    {
      id: 'status_badge',
      header: 'Status',
      accessor: row => getStatusBadge(row.status),
      width: '100px',
      sortable: true,
    },
    {
      id: 'actions',
      header: 'Actions',
      accessor: row => (
        <div className={styles.actionButtons}>
          <button
            className={styles.actionButton}
            onClick={e => {
              e.stopPropagation();
              setSelectedChatId(row.id);
            }}
            title='View chat'
          >
            <FiEye />
          </button>
          <button
            className={styles.actionButton}
            onClick={e => handleUpdateStatus(row.id, 'archived', e)}
            title='Archive chat'
          >
            <FiFlag />
          </button>
          <button
            className={styles.actionButton}
            onClick={e => handleDeleteChat(row.id, e)}
            title='Delete chat'
          >
            <FiTrash />
          </button>
        </div>
      ),
      width: '120px',
      align: 'center',
    },
  ];

  return (
    <PageContainer>
      <PageHeader>
        <HeaderLeft>
          <Heading level='h1'>Message Monitoring</Heading>
          <Text>Platform messaging activity and oversight</Text>
        </HeaderLeft>
      </PageHeader>

      <StatsBar>
        <StatCard>
          <StatIcon $color='#3b82f6'>
            <FiMessageSquare />
          </StatIcon>
          <StatDetails>
            <StatLabel>Total Chats</StatLabel>
            <StatValue>{stats.total}</StatValue>
          </StatDetails>
        </StatCard>

        <StatCard>
          <StatIcon $color='#10b981'>
            <FiCheckCircle />
          </StatIcon>
          <StatDetails>
            <StatLabel>Active Chats</StatLabel>
            <StatValue>{stats.active}</StatValue>
          </StatDetails>
        </StatCard>

        <StatCard>
          <StatIcon $color='#8b5cf6'>
            <FiMessageSquare />
          </StatIcon>
          <StatDetails>
            <StatLabel>Total Messages</StatLabel>
            <StatValue>{stats.messages}</StatValue>
          </StatDetails>
        </StatCard>

        <StatCard>
          <StatIcon $color='#f59e0b'>
            <FiAlertCircle />
          </StatIcon>
          <StatDetails>
            <StatLabel>Avg Messages/Chat</StatLabel>
            <StatValue>{stats.avgMessages}</StatValue>
          </StatDetails>
        </StatCard>
      </StatsBar>

      <FilterBar>
        <SearchInputWrapper>
          <FiSearch />
          <Input
            type='text'
            placeholder='Search conversations, participants, or messages...'
            value={searchQuery}
            onChange={e => setSearchQuery(e.target.value)}
          />
        </SearchInputWrapper>

        <FilterGroup>
          <FilterLabel>Status</FilterLabel>
          <Select value={statusFilter} onChange={e => setStatusFilter(e.target.value)}>
            <option value='all'>All Statuses</option>
            <option value='active'>Active</option>
            <option value='archived'>Archived</option>
            <option value='blocked'>Blocked</option>
            <option value='closed'>Closed</option>
          </Select>
        </FilterGroup>
      </FilterBar>

      {chatsError && (
        <div className={styles.errorBanner}>
          Error loading chats: {chatsError instanceof Error ? chatsError.message : 'Unknown error'}
        </div>
      )}

      <DataTable
        columns={columns}
        data={chats}
        loading={loading}
        emptyMessage='No conversations found matching your criteria'
        onRowClick={chat => setSelectedChatId(chat.id)}
        getRowId={chat => chat.id}
      />

      <ChatDetailModal
        isOpen={!!selectedChatId}
        onClose={handleCloseChatModal}
        chatId={selectedChatId}
        onUpdate={refetch}
      />

      <ConfirmDialog {...confirmProps} />
    </PageContainer>
  );
};

export default Messages;
